INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-b0f95c3f-moex-00071', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '為辦理原住民族基本法第2條第4款所規定之部落核定作業，原住民族委員會訂有原住民族委員會辦 理部落核定作業要點。下列關於原住民族委員會辦理部落核定作業要點之規定的敘述，何者錯誤？', '["鄉（鎮、市）及區公所應依職權或轄內原住民之請求，邀集熟稔部落歷史文化之民眾，進行部落之 訪查及統計", "部落概況訪查表應載明之事項，包含人口數、戶數、家族、族別及其比例，也包含共同生活區域範圍", "鄉（鎮、市、區）公所完成部落之訪查及統計後，應依照原住民族委員會推動原住民族部落會議實 施要點舉辦部落會議，聽取族人意見，並應將部落概況訪查表公告於公所、村（里）辦公室及其他 原住民常出入之公開場所。公告期間不得少於30日", "鄉（鎮、市、區）公所公告期間屆滿時，如無須修正之內容時，鄉（鎮、市、區）公所應將公告內 容函送直轄市、縣（市）政府審查。經審查通過後，直轄市、縣（市）政府應於2週內將公告內容、 審查意見及審查會議紀錄函送原住民族委員會審核"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00072', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依據諮商取得原住民族部落同意參與辦法附件，下列那一種行為不屬於原住民族基本法第21條所指 涉的開發行為？', '["礦產或土石之鑽探、採取工程及其碎解、洗選、冶煉、儲庫等其他增進產能設施之興建、增進產能 或擴建", "觀光（休閒）飯店及旅（賓）館之興建或擴建", "核能、水力、火力、風力、太陽光、溫差、地熱之發電機組、設備、電廠、汽電共生廠及其輸電線 路、超高壓變電所之設置、興建或擴建", "原住民於其所有之原住民保留地之所為，且對原住民族之居住或生活環境無不良影響之虞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00073', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '原住民族委員會組織法是原住民族委員會之職掌以及重要職務設置的依據。請問，下列關於原住民族 委員會組織法中對委員會之委員的規範敘述，何者正確？', '["置委員17人至27人", "委員是由主任委員提請行政院院長就原住民族代表、有關機關代表及學者、專家派（聘）兼之", "委員中原住民族各族代表應至少1人，依聘用人員聘用條例聘用，其聘期隨主任委員異動而更易， 均為無給職", "委員應有三分之一以上人數具原住民族身分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00074', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '下列關於原住民族基本法第2條所定義事項之敘述，何者錯誤？', '["原住民族：係指既存於臺灣而為國家管轄內之傳統民族，包括阿美族、泰雅族、排灣族、布農族、 卑南族、魯凱族、鄒族、賽夏族、雅美族、邵族、噶瑪蘭族、太魯閣族及其他自認為原住民族並經 中央原住民族主管機關報請行政院核定之民族", "原住民族地區：係指原住民傳統居住，具有原住民族歷史淵源及文化特色，經中央原住民族主管機 關報請行政院核定之地區", "部落：係指原住民於原住民族地區一定區域內，依其傳統規範共同生活結合而成之團體，經中央原 住民族主管機關報請行政院核定者", "原住民族土地：係指原住民族傳統領域土地及既有原住民保留地"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00075', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '下列何者概念，係指以原住民族知識體系為主，確保原住民族於健康照護領域中獲得公平、適當之健 康服務，使其身分或文化得到適足保障？', '["健康正義", "健康平等", "文化適當性", "文化安全"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00076', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '依據原住民族工作權保障法規定，各級政府應設置原住民合作社輔導小組，而下列何者非原住民合作 社輔導考核及獎勵辦法中所規定之原住民合作社輔導小組成員？', '["合作社主管機關代表", "原住民事務主管機關代表", "目的事業主管機關代表", "原住民族社會經濟與勞動文化相關之學者專家"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00077', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '人體研究計畫諮詢取得原住民族同意與約定商業利益及其應用辦法乃依人體研究法第15條第2項規 定所訂定。請問下列關於該辦法內容之描述，何者錯誤？', '["辦法中所謂目標群體，是指人體研究計畫預期研究之原住民族或其所屬特定群體", "辦法中對於以研究原住民族為目的者之定義，包含：「以原住民族或部落為研究內容」、「研究檢體 之採集、研究資料之搜集及分析涉及原住民族或部落」，以及「研究結果之解釋涉及原住民族或部 落」", "中央原住民族主管機關及原住民族地區之鄉（鎮、市、區）公所，應設置諮詢會代表原住民族行使 同意權與約定商業利益及其應用事項。中央諮詢會之委員，包含由中央原住民族主管機關聘用之原 住民族各族委員，以及學者專家代表", "研究計畫於諮詢及取得目標群體之同意時，研究主持人及諮詢會會議或部落會議應進行約定之事 項，包含：「研究結果所衍生商業利益之回饋機制」、「目標群體於研究過程之參與機制」，以及「研 究成果所得技術之移轉機制」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00078', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '下列關於山坡地保育利用條例第37條規定的敘述，何者錯誤？', '["原住民取得原住民保留地所有權，如有移轉，以原住民為限", "經中央原住民族主管機關審認符合災害之預防、災害發生時之應變及災後之復原重建用地需求，得 由政府承受私有原住民保留地", "因私人上金錢給付義務之執行事件進入法拍的原住民保留地，應由政府優先承購取得", "國有原住民保留地出租衍生之收益，得作為原住民保留地管理、原住民族地區經濟發展及基礎設施 建設、原住民族自治費用，不受國有財產法第7條規定之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00079', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '有關原住民保留地開發管理辦法中對於原住民保留地之開發利用的規範，下列敘述何者錯誤？', '["為促進原住民保留地礦業、土石、觀光遊憩、加油站、農產品集貨場倉儲設施之興建、工業資源之 開發、原住民族文化保存、醫療保健、社會福利、郵電運輸、金融服務及其他經中央主管機關核定 事業，在不妨礙原住民生計及推行原住民族行政之原則下，優先輔導原住民或原住民機構、法人或 團體開發或興辦", "原住民或原住民機構、法人或團體為前項開發或興辦，申請租用原住民保留地時，應檢具開發或興 辦計畫圖說，申請該管鄉（鎮、市、區）公所提經原住民保留地土地權利審查委員會擬具審查意見， 層報中央主管機關核准，並俟取得目的事業主管機關核准開發或興辦文件後，租用原住民保留地； 每一租期不得超過6年，期滿後得依原規定程序申請續租", "原住民機構、法人或團體以外企業或未具原住民身分者申請承租開發或興辦，應由鄉（鎮、市、區） 公所先公告30日，公告期滿無原住民或原住民機構、法人或團體申請時，始得依規定辦理申請承 租開發或興辦", "上述原住民保留地承租人，若有轉租或由他人頂替者，應終止租約收回土地，其所投資之各項設施 不予補償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL),
  ('aboriginal-b0f95c3f-moex-00080', 'aboriginal-b0f95c3f', 'aboriginal-b0f95c3f-moex-112-6ed013db', 'sub-aboriginal-b0f95c3f-06', NULL, 'single_choice', '原住民族委員會依原住民保留地開發管理辦法第6條規定，訂有鄉鎮市區原住民保留地土地權利審查 委員會設置要點。請問，下列關於原住民保留地土地權利審查委員會之敘述，何者錯誤？', '["其設置主任委員1人，由鄉（鎮、市、區）長兼任；委員8人至12人，由鄉（鎮、市、區）公所 聘兼之", "委員會職掌包含原住民保留地之諮商同意結果審查事項", "委員會每月開會1次，必要時得開臨時會，均由主任委員召集之", "委員對於涉及本人、其配偶或三親等內血親之議案，應自行迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:59+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "613", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "機械工程"}'::jsonb, NULL)
